305→    override fun onScrollableViewInitialized(containerId: Int) {
306→        StatsFragmentBinding.bind(requireView()).appBarLayout.liftOnScrollTargetViewId = containerId
307→        initJetpackBanner(containerId)
308→    }
309→
310→    private fun initJetpackBanner(scrollableContainerId: Int) {
311→        if (jetpackBrandingUtils.shouldShowJetpackBranding()) {
312→            val screen = JetpackPoweredScreen.WithDynamicText.STATS
313→            binding?.root?.post {
314→                val jetpackBannerView = binding?.jetpackBanner?.root ?: return@post
315→                val scrollableView = binding?.root?.findViewById<View>(scrollableContainerId) as? RecyclerView
316→                    ?: return@post
317→
318→                jetpackBrandingUtils.showJetpackBannerIfScrolledToTop(jetpackBannerView, scrollableView)
319→                jetpackBrandingUtils.initJetpackBannerAnimation(jetpackBannerView, scrollableView)
320→                binding?.jetpackBanner?.jetpackBannerText?.text = uiHelpers.getTextOfUiString(
321→                    requireContext(),
322→                    jetpackBrandingUtils.getBrandingTextForScreen(screen)
323→                )
324→
325→                if (jetpackBrandingUtils.shouldShowJetpackPoweredBottomSheet()) {
326→                    binding?.jetpackBanner?.root?.setOnClickListener {
327→                        jetpackBrandingUtils.trackBannerTapped(screen)
328→                        JetpackPoweredBottomSheetFragment
329→                            .newInstance()
330→                            .show(childFragmentManager, JetpackPoweredBottomSheetFragment.TAG)
331→                    }
332→                }
333→            }
334→        }
335→    }
336→}
