338→class StatsPagerAdapter(private val parent: Fragment) : FragmentStateAdapter(parent) {
339→    private val statsTabs = if (statsTrafficTabEnabled) statsSectionsWithTrafficTab else statsSections
340→    override fun getItemCount(): Int = statsTabs.size
341→
342→    override fun createFragment(position: Int): Fragment {
343→        return StatsListFragment.newInstance(statsTabs[position])
344→    }
345→
346→    fun getTabTitle(position: Int): CharSequence {
347→        return parent.context?.getString(statsTabs[position].titleRes).orEmpty()
348→    }
349→}
