351→private class SelectedTabListener(val viewModel: StatsViewModel) : OnTabSelectedListener {
352→    private val statsTabs = if (statsTrafficTabEnabled) statsSectionsWithTrafficTab else statsSections
353→    override fun onTabReselected(tab: Tab?) {
354→        // Do nothing
355→    }
356→
357→    override fun onTabUnselected(tab: Tab?) {
358→        // Do nothing
359→    }
360→
361→    override fun onTabSelected(tab: Tab) {
362→        viewModel.onSectionSelected(statsTabs[tab.position])
363→    }
364→}
