206→    fun buildChange(
207→        previousValue: Long?,
208→        value: Long,
209→        positive: Boolean,
210→        isFormattedNumber: Boolean
211→    ): String? {
212→        return previousValue?.let {
213→            val difference = value - previousValue
214→            val percentage = when (previousValue) {
215→                value -> "0"
216→                0L -> percentFormatter.format(value = 100)
217→                else -> {
218→                    val percentageValue = difference.toFloat() / previousValue
219→                    percentFormatter.formatWithJavaLib(value = percentageValue, rounding = HALF_UP)
220→                }
221→            }
222→            val formattedDifference = mapLongToString(difference, isFormattedNumber)
223→            if (positive) {
224→                resourceProvider.getString(R.string.stats_traffic_increase, formattedDifference, percentage)
225→            } else {
226→                resourceProvider.getString(R.string.stats_traffic_change, formattedDifference, percentage)
227→            }
228→        }
229→    }
